1	import type { SelectV2Workspace } from "@superset/db/schema";
2	import { useLiveQuery } from "@tanstack/react-db";
3	import { useEffect, useMemo, useState } from "react";
4	import { useHostProjects } from "renderer/hooks/host-projects/useHostProjects";
5	import { useRecycleBinRetention } from "renderer/routes/_authenticated/_dashboard/stores/recycleBinRetention";
6	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
7	import {
8		APP_LAUNCH_ID,
9		type DashboardSidebarProjectRow,
10		getWorkspaceSidebarBucket,
11		isWithinRecycleBinWindow,
12		isWorkspaceSnoozed,
13		KANBAN_COMPLETED_COLUMN_ID,
14		KANBAN_COMPLETED_TAB_ORDER,
15		KANBAN_QUEUE_COLUMN_ID,
16		KANBAN_QUEUE_TAB_ORDER,
17		type KanbanCardRow,
18		type KanbanColumnRow,
19		kanbanBoundCardId,
20		type WorkspaceLocalStateRow,
21	} from "renderer/routes/_authenticated/providers/CollectionsProvider/dashboardSidebarLocal";
22	import type {
23		KanbanCardBucket,
24		KanbanCardView,
25		KanbanColumnView,
26	} from "../../types";
27	import {
28		buildCompletedContext,
29		getCompletedFilterRange,
30		isWithinCompletedRange,
31	} from "../../utils/completedFilter";
32	import { deadlineGroupKey } from "../../utils/deadlineUrgency";
33	import { deriveCardTitle } from "../../utils/deriveCardTitle";
34	
35	const TICK_INTERVAL_MS = 60_000;
36	const STARTER_COLUMN_NAME = "In Progress";
37	
38	// (DEADLINE-TIE-ORDER) Within a deadline tie group (same due day, or the
39	// no-deadline tail): cards the user explicitly drag-ordered in deadline mode
40	// (deadlineTabOrder set) come first in that order; never-ordered cards (new
41	// arrivals, changed deadlines, column moves) follow underneath in manual
42	// tabOrder. The manual order itself is never touched from deadline mode.
43	function deadlineTieBreak(a: KanbanCardView, b: KanbanCardView): number {
44		const oa = a.card.deadlineTabOrder;
45		const ob = b.card.deadlineTabOrder;
46		if (oa != null && ob != null) {
47			return oa - ob || a.card.tabOrder - b.card.tabOrder;
48		}
49		if (oa != null) return -1;
50		if (ob != null) return 1;
51		return a.card.tabOrder - b.card.tabOrder;
52	}
53	
54	// (KANBAN COMPLETED) The Completed column ignores sortMode entirely: most
55	// recently completed first (ties by manual tabOrder). Intra-column drags are
56	// no-ops there, so there is no manual order to preserve.
57	function sortCompletedCards(cards: KanbanCardView[]): KanbanCardView[] {
58		return [...cards].sort(
59			(a, b) =>
60				(b.card.completedAt ?? 0) - (a.card.completedAt ?? 0) ||
61				a.card.tabOrder - b.card.tabOrder,
62		);
63	}
64	
65	function sortCards(
66		cards: KanbanCardView[],
67		sortMode: string,
68	): KanbanCardView[] {
69		const next = [...cards];
70		if (sortMode === "deadline") {
71			// Display-only: soonest due DAY first (deadlineGroupKey — the same group
72			// identity the board's drag handler uses), no-deadline last; within a tie
73			// group the deadline-mode drag order wins (see deadlineTieBreak) and the
74			// manual tabOrder is preserved untouched underneath.
75			next.sort((a, b) => {
76				const ka = deadlineGroupKey(a.card.deadline);
77				const kb = deadlineGroupKey(b.card.deadline);
78				if (ka == null && kb == null) return deadlineTieBreak(a, b);
79				if (ka == null) return 1;
80				if (kb == null) return -1;
81				return ka - kb || deadlineTieBreak(a, b);
82			});
83		} else {
84			next.sort((a, b) => a.card.tabOrder - b.card.tabOrder);
85		}
86		return next;
87	}
88	
89	/** Bucket for an UNBOUND (Queued) card, from its own delete/snooze/archive
90	 * fields. (RECYCLE-BIN) deletedAt wins first — a soft-deleted card shows ONLY in
91	 * the bin, mirroring getWorkspaceSidebarBucket's deleted-first precedence. */
92	function queuedCardBucket(card: KanbanCardRow, now: number): KanbanCardBucket {
93		if (card.deletedAt != null) return "deleted";
94		if (card.archivedAt != null) return "archived";
95		if (isWorkspaceSnoozed(card, now)) return "snoozed";
96		return "active";
97	}
98	
99	export interface UseKanbanDataResult {
100		isReady: boolean;
101		columns: KanbanColumnView[];
102		now: number;
103	}
104	
105	/**
106	 * The board's read model + reconcile. Live-queries the local Kanban collections
107	 * joined against branches (v2Workspaces) and projects, materialises one card per
108	 * branch and drops cards for deleted branches (ready-gated, per AGENTS rule 9),
109	 * and classifies every card into active / snoozed / archived. Also owns a gated
110	 * 60s tick that auto-unsnoozes expired Queued cards (bound cards are handled by
111	 * the sidebar's own ticker).
112	 */
113	export function useKanbanData(): UseKanbanDataResult {
114		const collections = useCollections();
115	
116		const { data: columnRows = [], isReady: columnsReady } = useLiveQuery(
117			(q) => q.from({ c: collections.v2KanbanColumns }),
118			[collections],
119		);
120		const { data: cardRows = [], isReady: cardsReady } = useLiveQuery(
121			(q) => q.from({ c: collections.v2KanbanCards }),
122			[collections],
123		);
124		const { data: workspaceRows = [], isReady: workspacesReady } = useLiveQuery(
125			(q) => q.from({ w: collections.v2Workspaces }),
126			[collections],
127		);
128		// Projects are fully local now — sourced from the host fan-out
129		// (useHostProjects), keyed by projectKey which equals a workspace's
130		// projectId. Upstream retired the `v2Projects` Electric collection.
131		const { projects: hostProjects } = useHostProjects();
132		const { data: localStateRows = [], isReady: localStateReady } = useLiveQuery(
133			(q) => q.from({ s: collections.v2WorkspaceLocalState }),
134			[collections],
135		);
136		const { data: sidebarProjectRows = [], isReady: sidebarProjectsReady } =
137			useLiveQuery(
138				(q) => q.from({ sp: collections.v2SidebarProjects }),
139				[collections],
140			);
141	
142		const isReady =
143			columnsReady &&
144			cardsReady &&
145			workspacesReady &&
146			localStateReady &&
147			sidebarProjectsReady;
148	
149		const [now, setNow] = useState(() => Date.now());
150	
151		// (RECYCLE-BIN) The device-local retention window is a DISPLAY filter for the
152		// per-column bin: cards deleted within the last N days show by default; older
153		// ones collapse behind the section's "Show all" toggle. Nothing is purged.
154		const retentionDays = useRecycleBinRetention((s) => s.retentionDays);
155	
156		// Gated tick: only run while something time-sensitive is pending (a snoozed
157		// card, or any deadline that could flip yellow→red across a day boundary).
158		const hasTimeSensitive = useMemo(() => {
159			// Only deadlines + TIMED snoozes need the wall-clock tick. An "until next
160			// launch" snooze (snoozeLaunchId) can't expire during this launch, so it
161			// must NOT keep the 60s ticker alive forever. (KANBAN COMPLETED) an
162			// active "Last month" filter is also wall-clock-relative — its range
163			// flips at a month boundary, so it keeps the tick alive too ("custom"
164			// ranges are static and "all" filters nothing).
165			return (
166				(cardRows as KanbanCardRow[]).some(
167					// (RECYCLE-BIN) a soft-deleted UNBOUND card's deletedAt is wall-clock-
168					// relative too: it crosses the retention boundary into recycleBinHidden
169					// without a tick. Keep the ticker alive while any bin item exists.
170					(c) =>
171						c.deadline != null || c.snoozeUntil != null || c.deletedAt != null,
172				) ||
173				// (RECYCLE-BIN) a soft-deleted BOUND card carries its deletedAt on the
174				// branch's local state, not the card — gate on that too.
175				(localStateRows as WorkspaceLocalStateRow[]).some(
176					(s) => s.sidebarState.deletedAt != null,
177				) ||
178				(columnRows as KanbanColumnRow[]).some(
179					(c) => c.isCompleted && c.completedFilter === "last-month",
180				)
181			);
182		}, [cardRows, columnRows, localStateRows]);
183		useEffect(() => {
184			if (!hasTimeSensitive) return;
185			const id = setInterval(() => setNow(Date.now()), TICK_INTERVAL_MS);
186			return () => clearInterval(id);
187		}, [hasTimeSensitive]);
188	
189		const workspaceById = useMemo(() => {
190			const map = new Map<string, SelectV2Workspace>();
191			for (const w of workspaceRows as SelectV2Workspace[]) map.set(w.id, w);
192			return map;
193		}, [workspaceRows]);
194	
195		const projectNameById = useMemo(() => {
196			const map = new Map<string, string>();
197			for (const p of hostProjects) map.set(p.projectKey, p.name);
198			return map;
199		}, [hostProjects]);
200	
201		const localStateByWorkspace = useMemo(() => {
202			const map = new Map<string, WorkspaceLocalStateRow>();
203			for (const s of localStateRows as WorkspaceLocalStateRow[]) {
204				map.set(s.workspaceId, s);
205			}
206			return map;
207		}, [localStateRows]);
208	
209		// Project-level sidebar membership. "Remove project from sidebar" deletes
210		// the v2SidebarProjects row AND the project's per-workspace local state, so
211		// the per-workspace bucket check alone can't see the removal (empty state
212		// buckets "active"). A project absent from the left bar must not surface on
213		// the board either.
214		const sidebarProjectIds = useMemo(() => {
215			const set = new Set<string>();
216			for (const sp of sidebarProjectRows as DashboardSidebarProjectRow[]) {
217				set.add(sp.projectId);
218			}
219			return set;
220		}, [sidebarProjectRows]);
221	
222		// --- Reconcile (ready-gated; idempotent via get-before-write) -------------
223		// biome-ignore lint/correctness/useExhaustiveDependencies: columnRows/cardRows are deliberate re-run triggers — the reconcile reads the collections' state imperatively, so it must re-fire when rows change.
224		useEffect(() => {
225			if (!isReady) return;
226	
227			// 1. Seed the fixed Queued column.
228			if (!collections.v2KanbanColumns.get(KANBAN_QUEUE_COLUMN_ID)) {
229				collections.v2KanbanColumns.insert({
230					id: KANBAN_QUEUE_COLUMN_ID,
231					name: "Queued",
232					tabOrder: KANBAN_QUEUE_TAB_ORDER,
233					isQueue: true,
234					isCompleted: false,
235					sortMode: "manual",
236					completedFilter: "all",
237					completedFilterFrom: null,
238					completedFilterTo: null,
239					showSnoozed: false,
240					showArchived: false,
241					snoozedCollapsed: false,
242					archivedCollapsed: false,
243					createdAt: Date.now(),
244				});
245			}
246	
247			// 1b. Seed the fixed FINAL Completed column (KANBAN COMPLETED).
248			if (!collections.v2KanbanColumns.get(KANBAN_COMPLETED_COLUMN_ID)) {
249				collections.v2KanbanColumns.insert({
250					id: KANBAN_COMPLETED_COLUMN_ID,
251					name: "Completed",
252					tabOrder: KANBAN_COMPLETED_TAB_ORDER,
253					isQueue: false,
254					isCompleted: true,
255					sortMode: "manual",
256					completedFilter: "all",
257					completedFilterFrom: null,
258					completedFilterTo: null,
259					showSnoozed: false,
260					showArchived: false,
261					snoozedCollapsed: false,
262					archivedCollapsed: false,
263					createdAt: Date.now(),
264				});
265			}
266	
267			// 2. Ensure ≥1 custom column (the landing column for new branches).
268			// Completed is excluded EXACTLY like the Queue: were it a landing
269			// candidate, a board with no custom columns would auto-complete every
270			// newly-materialised branch.
271			const currentColumns = Array.from(
272				collections.v2KanbanColumns.state.values(),
273			);
274			const customColumns = currentColumns
275				.filter(
276					(c) =>
277						!c.isQueue &&
278						c.id !== KANBAN_QUEUE_COLUMN_ID &&
279						!c.isCompleted &&
280						c.id !== KANBAN_COMPLETED_COLUMN_ID,
281				)
282				.sort((a, b) => a.tabOrder - b.tabOrder);
283			let landingColumnId: string;
284			if (customColumns.length === 0) {
285				landingColumnId = crypto.randomUUID();
286				collections.v2KanbanColumns.insert({
287					id: landingColumnId,
288					name: STARTER_COLUMN_NAME,
289					tabOrder: 1,
290					isQueue: false,
291					isCompleted: false,
292					sortMode: "manual",
293					completedFilter: "all",
294					completedFilterFrom: null,
295					completedFilterTo: null,
296					showSnoozed: false,
297					showArchived: false,
298					snoozedCollapsed: false,
299					archivedCollapsed: false,
300					createdAt: Date.now(),
301				});
302			} else {
303				landingColumnId = customColumns[0].id;
304			}
305	
306			// 3. Materialise a card for every non-hidden branch lacking one.
307			const existingCards = Array.from(collections.v2KanbanCards.state.values());
308			// Defensive dup-guard: a branch is "covered" if ANY card already points at
309			// it (not just the deterministic id), so we never create a second card.
310			const coveredWorkspaceIds = new Set(
311				existingCards
312					.map((c) => c.workspaceId)
313					.filter((id): id is string => id != null),
314			);
315			let nextOrder =
316				existingCards
317					.filter((c) => c.columnId === landingColumnId)
318					.reduce((max, c) => Math.max(max, c.tabOrder), 0) + 1;
319			for (const branch of workspaceRows as SelectV2Workspace[]) {
320				// Project removed from the sidebar → none of its branches get cards.
321				if (!sidebarProjectIds.has(branch.projectId)) continue;
322				const local = localStateByWorkspace.get(branch.id);
323				const bucket = getWorkspaceSidebarBucket(
324					local?.sidebarState ?? {},
325					Date.now(),
326					branch.type,
327				);
328				// A removed-from-sidebar (hidden, non-archived) branch is not
329				// representable on the board either.
330				if (bucket === "hidden") continue;
331				const cardId = kanbanBoundCardId(branch.id);
332				if (collections.v2KanbanCards.get(cardId)) continue;
333				if (coveredWorkspaceIds.has(branch.id)) continue;
334				// (KANBAN COMPLETED) a completed branch whose card was lost (e.g. a
335				// cleared cards blob) re-materialises INTO the Completed column with
336				// its sidebar stamp as the date — never into the landing column.
337				const isCompletedBranch = bucket === "completed";
338				collections.v2KanbanCards.insert({
339					id: cardId,
340					columnId: isCompletedBranch
341						? KANBAN_COMPLETED_COLUMN_ID
342						: landingColumnId,
343					tabOrder: isCompletedBranch ? 0 : nextOrder++,
344					title: deriveCardTitle(branch),
345					description: null,
346					deadline: null,
347					deadlineTabOrder: null,
348					workspaceId: branch.id,
349					snoozeUntil: null,
350					snoozeLaunchId: null,
351					archivedAt: null,
352					completedAt: isCompletedBranch
353						? (local?.sidebarState.completedAt ?? Date.now())
354						: null,
355					completedContext: isCompletedBranch
356						? buildCompletedContext(
357								projectNameById.get(branch.projectId) ?? null,
358								branch.branch,
359							)
360						: null,
361					createdAt: Date.now(),
362				});
363			}
364	
365			// 4. Drop bound cards whose branch is gone (branch deleted → card gone) —
366			// EXCEPT completed cards: those survive as FROZEN records (title +
367			// completedContext snapshot) so deleting a merged branch never erases the
368			// work from the user's completed-history reports. workspaceId stays set,
369			// so a transiently-missing workspace row re-binds with no duplicate.
370			for (const card of Array.from(collections.v2KanbanCards.state.values())) {
371				if (card.workspaceId && !workspaceById.has(card.workspaceId)) {
372					if (card.columnId === KANBAN_COMPLETED_COLUMN_ID) continue;
373					collections.v2KanbanCards.delete(card.id);
374				}
375			}
376	
377			// 5. Heal the two-writer pair (KANBAN COMPLETED). Card placement is the
378			// single intent signal — complete/uncomplete write the card transaction
379			// FIRST, so a crash between the two transactions always converges toward
380			// the card's column here:
381			//   (a) card in Completed but branch not completed → re-stamp the branch
382			//   (b) branch completed but card elsewhere → clear the branch
383			for (const card of Array.from(collections.v2KanbanCards.state.values())) {
384				if (!card.workspaceId) continue;
385				const ws = workspaceById.get(card.workspaceId);
386				if (!ws) continue; // frozen record (or pending prune) — nothing to heal
387				// While a project is removed from the sidebar its local-state rows are
388				// deliberately deleted — don't resurrect them from here.
389				if (!sidebarProjectIds.has(ws.projectId)) continue;
390				const local = localStateByWorkspace.get(card.workspaceId);
391				const bucket = getWorkspaceSidebarBucket(
392					local?.sidebarState ?? {},
393					Date.now(),
394					ws.type,
395				);
396				const inCompleted = card.columnId === KANBAN_COMPLETED_COLUMN_ID;
397				if (
398					inCompleted &&
399					bucket !== "completed" &&
400					bucket !== "hidden" &&
401					ws.type !== "main"
402				) {
403					const completedAt = card.completedAt ?? Date.now();
404					// Decide insert-vs-update from the LIVE collection state, not the
405					// render snapshot (`local`): useKanbanData runs in two instances
406					// (the dashboard-level KanbanReconciler AND the mounted board), and
407					// both can see a stale "no row" in the same commit cycle — the
408					// second insert would throw a duplicate-key error. The live
409					// get-before-write makes the second instance update instead.
410					if (collections.v2WorkspaceLocalState.get(card.workspaceId)) {
411						collections.v2WorkspaceLocalState.update(
412							card.workspaceId,
413							(draft) => {
414								draft.sidebarState.completedAt = completedAt;
415								draft.sidebarState.isHidden = true;
416								draft.sidebarState.archivedAt = null;
417								draft.sidebarState.snoozeUntil = null;
418								draft.sidebarState.snoozeLaunchId = null;
419							},
420						);
421					} else {
422						// No local-state row (e.g. the project was just re-added to the
423						// sidebar): the completion must be re-asserted via INSERT or the
424						// branch would resurface in the active lane while its card sits in
425						// Completed. Same minimal row hideWorkspaceInSidebar seeds.
426						collections.v2WorkspaceLocalState.insert({
427							workspaceId: card.workspaceId,
428							createdAt: new Date(),
429							sidebarState: {
430								projectId: ws.projectId,
431								tabOrder: 0,
432								sectionId: null,
433								isHidden: true,
434								completedAt,
435							},
436							paneLayout: { version: 1, tabs: [], activeTabId: null },
437						});
438					}
439					if (card.completedAt == null) {
440						// Backfill the report datum from the stamp we just asserted.
441						collections.v2KanbanCards.update(card.id, (draft) => {
442							draft.completedAt = completedAt;
443						});
444					}
445				} else if (
446					inCompleted &&
447					bucket === "completed" &&
448					card.completedAt == null
449				) {
450					// Card transaction landed without its date (crash mid-complete):
451					// backfill from the sidebar stamp.
452					const stamp = local?.sidebarState.completedAt ?? Date.now();
453					collections.v2KanbanCards.update(card.id, (draft) => {
454						draft.completedAt = stamp;
455					});
456				} else if (!inCompleted && bucket === "completed") {
457					if (collections.v2WorkspaceLocalState.get(card.workspaceId)) {
458						collections.v2WorkspaceLocalState.update(
459							card.workspaceId,
460							(draft) => {
461								draft.sidebarState.completedAt = null;
462								draft.sidebarState.isHidden = false;
463								draft.sidebarState.archivedAt = null;
464							},
465						);
466					}
467				}
468			}
469		}, [
470			isReady,
471			collections,
472			workspaceRows,
473			workspaceById,
474			localStateByWorkspace,
475			sidebarProjectIds,
476			projectNameById,
477			columnRows,
478			cardRows,
479		]);
480	
481		// --- Auto-unsnooze expired QUEUED cards (mirrors the sidebar ticker) -------
482		useEffect(() => {
483			if (!isReady) return;
484			for (const card of cardRows as KanbanCardRow[]) {
485				if (card.workspaceId) continue; // bound cards: sidebar ticker handles it
486				const expiredTimed =
487					typeof card.snoozeUntil === "number" && card.snoozeUntil <= now;
488				const staleLaunch =
489					card.snoozeLaunchId != null && card.snoozeLaunchId !== APP_LAUNCH_ID;
490				if (expiredTimed || staleLaunch) {
491					if (!collections.v2KanbanCards.get(card.id)) continue;
492					collections.v2KanbanCards.update(card.id, (draft) => {
493						draft.snoozeUntil = null;
494						draft.snoozeLaunchId = null;
495					});
496				}
497			}
498		}, [isReady, now, cardRows, collections]);
499	
500		// --- Build the rendered column views --------------------------------------
501		const columns = useMemo<KanbanColumnView[]>(() => {
502			const orderedColumns = [...(columnRows as KanbanColumnRow[])].sort(
503				(a, b) => a.tabOrder - b.tabOrder,
504			);
505			return orderedColumns.map((column) => {
506				const active: KanbanCardView[] = [];
507				const snoozed: KanbanCardView[] = [];
508				const archived: KanbanCardView[] = [];
509				// (RECYCLE-BIN) Soft-deleted cards in this column (bound branch deleted, or
510				// an unbound card's deletedAt). Each carries its resolved deletedAt so the
511				// retention window can split them into shown-by-default vs older-collapsed.
512				const deleted: { view: KanbanCardView; deletedAt: number | null }[] = [];
513				for (const card of cardRows as KanbanCardRow[]) {
514					if (card.columnId !== column.id) continue;
515	
516					let workspace: SelectV2Workspace | null = null;
517					let projectName: string | null = null;
518					let bucket: KanbanCardBucket;
519					// (RECYCLE-BIN) The deletedAt that feeds the retention window: a bound
520					// card reads the branch's sidebarState (one source of truth), an unbound
521					// card reads its own field. Only meaningful when bucket === "deleted".
522					let deletedAt: number | null = null;
523	
524					if (card.workspaceId) {
525						workspace = workspaceById.get(card.workspaceId) ?? null;
526						if (!workspace) {
527							// (KANBAN COMPLETED) FROZEN record: a completed card whose branch
528							// was deleted renders from its title/completedContext snapshot —
529							// it's a history record, so no project gate either (there is no
530							// live projectId to check). Anywhere else a missing workspace is
531							// just pending cleanup — don't render a ghost.
532							if (card.columnId !== KANBAN_COMPLETED_COLUMN_ID) continue;
533							bucket = "active";
534						} else {
535							// HIDE (never delete) cards of projects removed from the sidebar —
536							// re-adding the project restores them with column/deadline intact.
537							if (!sidebarProjectIds.has(workspace.projectId)) continue;
538							projectName = projectNameById.get(workspace.projectId) ?? null;
539							const local = localStateByWorkspace.get(workspace.id);
540							const wsBucket = getWorkspaceSidebarBucket(
541								local?.sidebarState ?? {},
542								now,
543								workspace.type,
544							);
545							if (wsBucket === "hidden") continue;
546							// "completed" has no kanban section — completed cards render in
547							// the Completed column's main (active) list.
548							bucket = wsBucket === "completed" ? "active" : wsBucket;
549							if (bucket === "deleted") {
550								deletedAt = local?.sidebarState.deletedAt ?? null;
551							}
552						}
553					} else {
554						bucket = queuedCardBucket(card, now);
555						if (bucket === "deleted") deletedAt = card.deletedAt;
556					}
557	
558					// Bound cards take their title LIVE from the branch (same object the
559					// sidebar reads — can't diverge); the stored card.title is only the
560					// source for unbound (Queued) cards.
561					const title = workspace ? deriveCardTitle(workspace) : card.title;
562					const view: KanbanCardView = {
563						card,
564						workspace,
565						projectName,
566						bucket,
567						title,
568					};
569					if (bucket === "deleted") deleted.push({ view, deletedAt });
570					else if (bucket === "archived") archived.push(view);
571					else if (bucket === "snoozed") snoozed.push(view);
572					else active.push(view);
573				}
574				// (RECYCLE-BIN) Sort the bin deletedAt DESC (most-recently deleted first),
575				// then split on the retention window: items within the last N days show by
576				// default; older ones surface only via the section's "Show all" footer.
577				const sortedDeleted = [...deleted].sort(
578					(a, b) => (b.deletedAt ?? 0) - (a.deletedAt ?? 0),
579				);
580				const recycleBin: KanbanCardView[] = [];
581				const recycleBinHidden: KanbanCardView[] = [];
582				for (const entry of sortedDeleted) {
583					if (isWithinRecycleBinWindow(entry.deletedAt, retentionDays, now)) {
584						recycleBin.push(entry.view);
585					} else {
586						recycleBinHidden.push(entry.view);
587					}
588				}
589				if (column.isCompleted) {
590					// (KANBAN COMPLETED) date-sorted (latest first) + the persisted
591					// completed-date filter; the filtered-out count surfaces as a footer
592					// so a fresh drop "vanishing" under a narrow filter is explainable.
593					const sorted = sortCompletedCards(active);
594					const range = getCompletedFilterRange(column, now);
595					const filtered = range
596						? sorted.filter((v) =>
597								isWithinCompletedRange(v.card.completedAt, range),
598							)
599						: sorted;
600					return {
601						column,
602						active: filtered,
603						snoozed: sortCards(snoozed, column.sortMode),
604						archived: sortCards(archived, column.sortMode),
605						recycleBin,
606						recycleBinHidden,
607						hiddenByFilter: sorted.length - filtered.length,
608					};
609				}
610				return {
611					column,
612					active: sortCards(active, column.sortMode),
613					snoozed: sortCards(snoozed, column.sortMode),
614					archived: sortCards(archived, column.sortMode),
615					recycleBin,
616					recycleBinHidden,
617					hiddenByFilter: 0,
618				};
619			});
620		}, [
621			columnRows,
622			cardRows,
623			workspaceById,
624			projectNameById,
625			localStateByWorkspace,
626			sidebarProjectIds,
627			retentionDays,
628			now,
629		]);
630	
631		return { isReady, columns, now };
632	}
