5	export function getSidebarWorkspaceIsHidden(
6		workspace: SidebarWorkspaceVisibilitySource,
7	): boolean {
8		if ("sidebarState" in workspace) {
9			return workspace.sidebarState.isHidden === true;
10		}
11		return workspace.isHidden === true;
12	}
13	
14	export function isSidebarWorkspaceVisible(
15		workspace: SidebarWorkspaceVisibilitySource,
16	): boolean {
17		return !getSidebarWorkspaceIsHidden(workspace);
18	}
19	
20	export function getVisibleSidebarWorkspaces<
21		Workspace extends SidebarWorkspaceVisibilitySource,
22	>(workspaces: readonly Workspace[]): Workspace[] {
23		return workspaces.filter(isSidebarWorkspaceVisible);
24	}
25	
26	/**
27	 * A `main` workspace is auto-included in the sidebar when the user hasn't
28	 * explicitly placed it (no local-state row), it lives on this machine, and its
29	 * project is one the user added to their sidebar. Shared by the sidebar tree
30	 * builder and the notification/ports visibility filters so they agree on what
31	 * "in the sidebar" means.
32	 */
33	export function isAutoIncludedLocalMainWorkspace(
34		workspace: { id: string; hostId: string; projectId: string },
35		{
36			localStateWorkspaceIds,
37			sidebarProjectIds,
38			machineId,
39		}: {
40			localStateWorkspaceIds: ReadonlySet<string>;
41			sidebarProjectIds: ReadonlySet<string>;
42			machineId: string | null;
43		},
44	): boolean {
45		return (
46			!localStateWorkspaceIds.has(workspace.id) &&
47			workspace.hostId === machineId &&
48			sidebarProjectIds.has(workspace.projectId)
49		);
50	}
51	
52	// ---------------------------------------------------------------------------
53	// Snooze / Archive — thread states layered on top of the local sidebar row.
54	//
55	// archived := sidebarState.archivedAt != null   (an explicit archive timestamp).
56	//             archiveWorkspace also sets isHidden so the row leaves the active
57	//             lane, but the ARCHIVED signal is archivedAt — NOT raw isHidden.
58	//             Raw isHidden WITHOUT a timestamp is still produced by whole-project
59	//             teardown and by LEGACY hidden mains (pre MASTER-ARCHIVE-ONLY, when a
60	//             master-card remove hid instead of archiving) — these must not
61	//             surface as archived. A master-card remove now archives (archivedAt).
62	// snoozed  := snooze timer still in the future, OR an "until next launch"
63	//             snooze whose launch id matches THIS app launch.
64	// active   := neither.
65	//
66	// All local-only and visual-only — these helpers only classify; nothing here
67	// touches a worktree or a running session.
68	// ---------------------------------------------------------------------------
69	
70	/** One id per app launch. An "until next launch" snooze stores this; on the
71	 * next launch the id differs, so the thread is no longer snoozed. */
72	export const APP_LAUNCH_ID = crypto.randomUUID();
73	
74	interface SidebarWorkspaceStateFields {
75		isHidden?: boolean | null;
76		archivedAt?: number | null;
77		snoozeUntil?: number | null;
78		snoozeLaunchId?: string | null;
79		completedAt?: number | null;
80		// (RECYCLE-BIN) Soft-delete timestamp — presence makes the thread bucket
81		// "deleted" (highest precedence), surfacing it ONLY in the Recycle Bin.
82		deletedAt?: number | null;
83	}
84	
85	type SidebarWorkspaceStateSource =
86		| (SidebarWorkspaceStateFields & { type?: string | null })
87		| { sidebarState: SidebarWorkspaceStateFields; type?: string | null };
88	
89	function readSidebarWorkspaceState(
90		workspace: SidebarWorkspaceStateSource,
91	): SidebarWorkspaceStateFields {
92		return "sidebarState" in workspace ? workspace.sidebarState : workspace;
93	}
94	
95	/** The workspace "type" (e.g. "main") lives on the workspace row, alongside the
96	 * sidebar state. Reading it lets the classifier treat a removed non-main thread
97	 * as archived while keeping a removed main workspace merely hidden. */
98	function readWorkspaceType(
99		workspace: SidebarWorkspaceStateSource,
100	): string | null | undefined {
101		return (workspace as { type?: string | null }).type;
102	}
103	
104	/** (RECYCLE-BIN) A thread is soft-deleted while `deletedAt` is set. The Recycle
105	 * Bin is the ONLY surface for it — the bucket classifier checks this FIRST so a
106	 * deleted thread never reappears under Archived/Snoozed/Completed. Visual-only;
107	 * the worktree and branch are untouched until a permanent destroy. */
108	export function isWorkspaceDeleted(
109		workspace: SidebarWorkspaceStateSource,
110	): boolean {
111		return readSidebarWorkspaceState(workspace).deletedAt != null;
112	}
113	
114	export function isWorkspaceArchived(
115		workspace: SidebarWorkspaceStateSource,
116		workspaceType?: string | null,
117	): boolean {
118		const state = readSidebarWorkspaceState(workspace);
119		if (state.archivedAt != null) return true;
120		// A non-main thread removed via "Remove from Sidebar" (isHidden, no archive
121		// timestamp) surfaces under Archived — recoverable. A removed main/pinned
122		// workspace stays fully hidden and is never treated as archived.
123		const type = workspaceType ?? readWorkspaceType(workspace);
124		return state.isHidden === true && type !== "main";
125	}
126	
127	export function isWorkspaceSnoozed(
128		workspace: SidebarWorkspaceStateSource,
129		nowMs: number = Date.now(),
130	): boolean {
131		const state = readSidebarWorkspaceState(workspace);
132		if (state.snoozeLaunchId != null && state.snoozeLaunchId === APP_LAUNCH_ID) {
133			return true;
134		}
135		return typeof state.snoozeUntil === "number" && state.snoozeUntil > nowMs;
136	}
137	
138	export type SidebarWorkspaceBucket =
139		| "active"
140		| "snoozed"
141		| "archived"
142		| "hidden"
143		| "completed"
144		| "deleted";
145	
146	export function getWorkspaceSidebarBucket(
147		workspace: SidebarWorkspaceStateSource,
148		nowMs: number = Date.now(),
149		workspaceType?: string | null,
150	): SidebarWorkspaceBucket {
151		// (RECYCLE-BIN) checked FIRST of all: deleteWorkspace also sets isHidden (and
152		// clears every other state flag), but a soft-deleted thread must surface ONLY
153		// in the Recycle Bin — never under Completed/Archived/Snoozed/Hidden. Restore
154		// clears deletedAt to return it to active.
155		if (isWorkspaceDeleted(workspace)) return "deleted";
156		// (KANBAN COMPLETED) checked next: completeWorkspace also sets isHidden so
157		// raw-visibility consumers hide the row, but isHidden + non-main would
158		// classify "archived" below and surface the thread under the project's
159		// Archived section. Completed threads have NO sidebar surface at all — the
160		// kanban Completed column is the only place they exist.
161		if (readSidebarWorkspaceState(workspace).completedAt != null) {
162			return "completed";
163		}
164		// Main rows can be snoozed/archived on purpose (the UI offers it). A main with
165		// archivedAt set buckets "archived" below; a main hidden WITHOUT an archive
166		// timestamp stays merely "hidden" — isWorkspaceArchived's `&& type !== "main"`
167		// keeps an accidental remove out of "archived" (so it still resurrects on
168		// reopen, never silently archived).
169		if (isWorkspaceArchived(workspace, workspaceType)) return "archived";
170		if (isWorkspaceSnoozed(workspace, nowMs)) return "snoozed";
171		// A removed non-main workspace (isHidden, no archive timestamp) is hidden
172		// outright — not archived, not snoozed, and NOT in the active lane.
173		if (readSidebarWorkspaceState(workspace).isHidden === true) return "hidden";
174		return "active";
175	}
176	
177	const HOUR_MS = 3_600_000;
178	const DAY_MS = 24 * HOUR_MS;
179	
180	/** (RECYCLE-BIN) Retention is a DISPLAY filter only — nothing is ever
181	 * auto-purged. Returns true when an item should be shown by default in the bin:
182	 * a missing timestamp is always shown, otherwise it's within the last
183	 * `retentionDays`. Older items are kept but collapsed behind the per-bin
184	 * "Show all" toggle. */
185	export function isWithinRecycleBinWindow(
186		deletedAt: number | null | undefined,
187		retentionDays: number,
188		nowMs: number = Date.now(),
189	): boolean {
190		if (deletedAt == null) return true;
191		return nowMs - deletedAt <= retentionDays * DAY_MS;
192	}
193	
194	export type SnoozeDuration =
195		| { kind: "next-launch" }
196		| { kind: "tomorrow" }
197		| { kind: "ms"; ms: number }
198		| { kind: "hours"; hours: number };
199	
200	export interface SnoozePresetOption {
201		id: string;
202		label: string;
203		duration: SnoozeDuration;
204	}
205	
206	/** Preset entries for the Snooze submenu, in display order. The custom
207	 * "N hours" entry is rendered separately as an inline field. */
208	export const SNOOZE_PRESET_OPTIONS: readonly SnoozePresetOption[] = [
209		{ id: "tomorrow", label: "Until tomorrow", duration: { kind: "tomorrow" } },
210		{ id: "1d", label: "1 day", duration: { kind: "ms", ms: DAY_MS } },
211		{ id: "3d", label: "3 days", duration: { kind: "ms", ms: 3 * DAY_MS } },
212		{ id: "1w", label: "1 week", duration: { kind: "ms", ms: 7 * DAY_MS } },
213		{
214			id: "next-launch",
215			label: "Until next launch",
216			duration: { kind: "next-launch" },
217		},
218	] as const;
219	
220	/** Resolve a chosen duration to a stored snooze value: an absolute epoch-ms
221	 * deadline, or the "next-launch" sentinel handled by the caller. */
222	export function computeSnoozeUntil(
223		duration: SnoozeDuration,
224		nowMs: number = Date.now(),
225	): number | "next-launch" {
226		switch (duration.kind) {
227			case "next-launch":
228				return "next-launch";
229			case "hours":
230				return nowMs + Math.max(1, Math.round(duration.hours * HOUR_MS));
231			case "ms":
232				return nowMs + duration.ms;
233			case "tomorrow": {
234				const tomorrow = new Date(nowMs);
235				tomorrow.setDate(tomorrow.getDate() + 1);
236				tomorrow.setHours(9, 0, 0, 0);
237				return tomorrow.getTime();
238			}
239		}
240	}
241	
242	/** Short label for how long a snooze has left: "launch", "5m", "3h", "2d". */
243	export function formatSnoozeRemaining(
244		snoozeUntil: number | null | undefined,
245		snoozeLaunchId: string | null | undefined,
246		nowMs: number = Date.now(),
247	): string {
248		if (
249			snoozeLaunchId != null &&
250			snoozeLaunchId === APP_LAUNCH_ID &&
251			(typeof snoozeUntil !== "number" || snoozeUntil <= nowMs)
252		) {
253			return "launch";
254		}
255		if (typeof snoozeUntil !== "number") return "";
256		const remaining = snoozeUntil - nowMs;
257		if (remaining <= 0) return "";
258		const minutes = Math.round(remaining / 60_000);
259		if (minutes < 60) return `${Math.max(1, minutes)}m`;
260		const hours = Math.round(minutes / 60);
261		if (hours < 24) return `${hours}h`;
262		return `${Math.round(hours / 24)}d`;
263	}
264

