612		const computedGroups = useMemo<DashboardSidebarProject[]>(() => {
613			const projectsById = new Map<
614				string,
615				DashboardSidebarProject & {
616					sectionMap: Map<string, DashboardSidebarSection>;
617					childEntries: Array<{
618						tabOrder: number;
619						child: DashboardSidebarProjectChild;
620					}>;
621					orphanedWorkspaces: Array<{
622						tabOrder: number;
623						workspace: DashboardSidebarWorkspace;
624					}>;
625				}
626			>();
627	
628			for (const project of sidebarProjects) {
629				projectsById.set(project.id, {
630					...project,
631					children: [],
632					snoozedWorkspaces: [],
633					archivedWorkspaces: [],
634					// (RECYCLE-BIN) full, unfiltered bin contents; the section component
635					// applies the retention window and derives its header count from this
636					// array's length.
637					deletedWorkspaces: [],
638					sectionMap: new Map(),
639					childEntries: [],
640					orphanedWorkspaces: [],
641				});
642			}
643	
644			for (const section of sidebarSections) {
645				const project = projectsById.get(section.projectId);
646				if (!project) continue;
647	
648				const sidebarSection: DashboardSidebarSection = {
649					...section,
650					workspaces: [],
651				};
652	
653				project.sectionMap.set(section.id, sidebarSection);
654				project.childEntries.push({
655					tabOrder: section.tabOrder,
656					child: {
657						type: "section",
658						section: sidebarSection,
659					},
660				});
661			}
662	
663			for (const workspace of visibleSidebarWorkspaces) {
664				const project = projectsById.get(workspace.projectId);
665				if (!project) continue;
666	
667				const hostType: DashboardSidebarWorkspace["hostType"] =
668					workspace.hostId === machineId ? "local-device" : "remote-device";
669	
670				const sidebarWorkspace: DashboardSidebarWorkspace = {
671					id: workspace.id,
672					projectId: workspace.projectId,
673					hostId: workspace.hostId,
674					hostType,
675					type: workspace.type,
676					hostIsOnline:
677						hostType === "remote-device" ? workspace.hostIsOnline : null,
678					accentColor: null,
679					name: workspace.name,
680					branch: workspace.branch,
681					pullRequest: pullRequestsByWorkspaceId.get(workspace.id) ?? null,
682					repoUrl:
683						project.githubOwner && project.githubRepoName
684							? `https://github.com/${project.githubOwner}/${project.githubRepoName}`
685							: null,
686					branchExistsOnRemote:
687						project.githubOwner !== null && project.githubRepoName !== null,
688					previewUrl: null,
689					needsRebase: null,
690					behindCount: null,
691					createdAt: workspace.createdAt,
692					updatedAt: workspace.updatedAt,
693					taskId: workspace.taskId,
694					pendingTransaction: workspace.pendingTransaction,
695					justReturned: justReturnedIds.has(workspace.id),
696				};
697	
698				if (workspace.sectionId) {
699					const section = project.sectionMap.get(workspace.sectionId);
