1	import type { SelectV2Workspace } from "@superset/db/schema";
2	import { buildHostRoutingKey } from "@superset/shared/host-routing";
3	import type { WorkspaceSnapshotPayload } from "@superset/workspace-client";
4	import { del as idbDel, get as idbGet, set as idbSet } from "idb-keyval";
5	
6	/**
7	 * A workspace row as served by a host (`workspace.list`) — the cloud row
8	 * shape plus the host-only extras.
9	 */
10	export interface HostWorkspaceRow extends SelectV2Workspace {
11		worktreePath: string;
12		worktreeExists: boolean;
13	}
14	
15	/** Merged item returned by useHostWorkspaces. */
16	export interface HostWorkspaceItem extends SelectV2Workspace {
17		worktreePath?: string;
18		worktreeExists?: boolean;
19		/** False when the row came from a snapshot/cloud and the host didn't answer. */
20		hostReachable: boolean;
21		/** "host" = served by a host (live or last-seen); "cloud" = Electric fallback. */
22		source: "host" | "cloud";
23	}
24	
25	export interface HostWorkspacesQueryTarget {
26		machineId: string;
27		organizationId: string;
28		/** Null when the host is known but unreachable (offline remote). */
29		hostUrl: string | null;
30		isLocal: boolean;
31	}
32	
33	export interface HostRowForTargets {
34		organizationId: string;
35		machineId: string;
36		isOnline: boolean;
37	}
38	
39	export function getHostWorkspacesQueryKey(
40		target: Pick<HostWorkspacesQueryTarget, "machineId" | "hostUrl">,
41	) {
42		return [
43			"host-service",
44			"workspaces",
45			"list",
46			target.machineId,
47			target.hostUrl,
48		] as const;
49	}
50	
51	/**
52	 * One target per known host: the local host always (direct URL), remote
53	 * hosts via relay when online, and a null-URL placeholder when offline so
54	 * the last-seen snapshot still renders.
55	 */
56	export function deriveHostWorkspacesQueryTargets({
57		activeHostUrl,
58		hosts,
59		machineId,
60		relayUrl,
61	}: {
62		activeHostUrl: string | null;
63		hosts: HostRowForTargets[];
64		machineId: string | null;
65		relayUrl: string;
66	}): HostWorkspacesQueryTarget[] {
67		const targets: HostWorkspacesQueryTarget[] = hosts.map((host) => {
68			const isLocal = host.machineId === machineId;
69			const hostUrl = isLocal
70				? activeHostUrl
71				: host.isOnline
72					? `${relayUrl}/hosts/${buildHostRoutingKey(host.organizationId, host.machineId)}`
73					: null;
74			return {
75				machineId: host.machineId,
76				organizationId: host.organizationId,
77				hostUrl,
78				isLocal,
79			};
80		});
81	
82		// The local host may not have a v2_hosts row yet (fresh install, stale
83		// Electric); it is still queryable directly.
84		if (
85			machineId &&
86			activeHostUrl &&
87			!targets.some((target) => target.machineId === machineId)
88		) {
89			targets.push({
90				machineId,
91				organizationId: hosts[0]?.organizationId ?? "",
92				hostUrl: activeHostUrl,
93				isLocal: true,
94			});
95		}
96	
97		return targets;
98	}
99	
100	const SNAPSHOT_KEY_PREFIX = "host-workspaces:v1";
101	
102	function snapshotKey(organizationId: string, machineId: string): string {
103		return `${SNAPSHOT_KEY_PREFIX}:${organizationId}:${machineId}`;
104	}
105	
106	/**
107	 * Last-seen per-host snapshots in IndexedDB. Dates survive the structured
108	 * clone, so rows round-trip as-is. Only affects offline visibility of
109	 * remote hosts — the local host answers live even offline. Persistence
110	 * failures are deliberately swallowed: the snapshot is a best-effort cache
111	 * and every failure mode degrades to "fetch live next time".
112	 */
113	export async function loadHostWorkspacesSnapshot(
114		organizationId: string,
115		machineId: string,
116	): Promise<HostWorkspaceRow[] | undefined> {
117		if (!organizationId) return undefined;
118		try {
119			return await idbGet<HostWorkspaceRow[]>(
120				snapshotKey(organizationId, machineId),
121			);
122		} catch {
123			return undefined;
124		}
125	}
126	
127	export function saveHostWorkspacesSnapshot(
128		organizationId: string,
129		machineId: string,
130		rows: HostWorkspaceRow[],
131	): void {
132		if (!organizationId) return;
133		void idbSet(snapshotKey(organizationId, machineId), rows).catch(() => {});
134	}
135	
136	export function clearHostWorkspacesSnapshot(
137		organizationId: string,
138		machineId: string,
139	): void {
140		if (!organizationId) return;
141		void idbDel(snapshotKey(organizationId, machineId)).catch(() => {});
142	}
143	
144	/**
145	 * Apply a workspace:changed event to a host's cached list. Created/updated
146	 * upsert from the event's snapshot payload; deleted removes the row.
147	 */
148	export function applyWorkspaceChangedEvent(
149		rows: HostWorkspaceRow[] | undefined,
150		event: {
151			eventType: "created" | "updated" | "deleted";
152			workspace: WorkspaceSnapshotPayload | null;
153		},
154		host: { organizationId: string; machineId: string },
155		workspaceId: string,
156	): HostWorkspaceRow[] | undefined {
157		if (event.eventType === "deleted") {
158			if (!rows) return rows;
159			const next = rows.filter((row) => row.id !== workspaceId);
160			return next.length === rows.length ? rows : next;
161		}
162		const snapshot = event.workspace;
163		if (!snapshot) return rows;
164		const existing = rows?.find((row) => row.id === snapshot.id);
165		const nextRow: HostWorkspaceRow = {
166			id: snapshot.id,
