1	import { useCallback, useMemo } from "react";
2	import { useHostProjects } from "renderer/hooks/host-projects/useHostProjects";
3	import { useDashboardSidebarState } from "renderer/routes/_authenticated/hooks/useDashboardSidebarState";
4	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
5	import {
6		APP_LAUNCH_ID,
7		getNextTabOrder,
8		KANBAN_COMPLETED_COLUMN_ID,
9		KANBAN_QUEUE_COLUMN_ID,
10		type KanbanCardRow,
11		kanbanBoundCardId,
12	} from "renderer/routes/_authenticated/providers/CollectionsProvider/dashboardSidebarLocal";
13	import { applyKanbanCardPatch } from "../../utils/applyKanbanCardPatch";
14	import { buildCompletedContext } from "../../utils/completedFilter";
15	import { getColumnDeleteTarget } from "../../utils/computeColumnDeleteTargets";
16	import { deriveCardTitle } from "../../utils/deriveCardTitle";
17	
18	export type CardDropKind = "ok" | "promote" | "reject";
19	
20	export interface DeleteColumnResult {
21		ok: boolean;
22		reason?: string;
23	}
24	
25	export interface UseKanbanActionsResult {
26		createQueuedCard: (title?: string) => string;
27		updateCard: (
28			cardId: string,
29			patch: {
30				title?: string;
31				description?: string | null;
32				deadline?: number | null;
33			},
34		) => void;
35		canDropCard: (
36			card: KanbanCardRow,
37			toColumnId: string,
38			workspaceType?: string | null,
39		) => CardDropKind;
40		applyCardOrder: (columnId: string, orderedCardIds: string[]) => void;
41		applyDeadlineTieOrder: (
42			orderedCardIds: string[],
43			resetCardIds?: string[],
44		) => void;
45		moveCardToColumn: (cardId: string, toColumnId: string) => void;
46		completePromote: (
47			queuedCardId: string,
48			workspaceId: string,
49			toColumnId: string,
50		) => void;
51		restoreQueuedCard: (
52			snapshot: KanbanCardRow,
53			optimisticWorkspaceId: string,
54		) => void;
55		rebindPromotedCard: (fromWorkspaceId: string, toWorkspaceId: string) => void;
56		addColumn: (name?: string) => string;
57		renameColumn: (columnId: string, name: string) => void;
58		deleteColumn: (columnId: string) => DeleteColumnResult;
59		reorderColumns: (orderedCustomIds: string[]) => void;
60		setColumnSortMode: (columnId: string, mode: "manual" | "deadline") => void;
61		setColumnSectionFlag: (
62			columnId: string,
63			field:
64				| "showSnoozed"
65				| "showArchived"
66				| "snoozedCollapsed"
67				| "archivedCollapsed"
68				| "showRecycleBin"
69				| "recycleBinCollapsed",
70			value: boolean,
71		) => void;
72		snoozeCard: (card: KanbanCardRow, until: number | "next-launch") => void;
73		unsnoozeCard: (card: KanbanCardRow) => void;
74		archiveCard: (card: KanbanCardRow) => void;
75		unarchiveCard: (card: KanbanCardRow) => void;
76		/** (RECYCLE-BIN) The default card "Delete" — SOFT, silent (no dialog/toast).
77		 * Bound cards delegate to deleteWorkspace (one source of truth on the branch's
78		 * sidebarState); an unbound (Queued) card stamps its own deletedAt. The
79		 * worktree/branch/sessions are untouched — exactly like Archive. */
80		deleteCard: (card: KanbanCardRow) => void;
81		/** (RECYCLE-BIN) Restore a soft-deleted card straight back to ACTIVE — bound
82		 * via restoreWorkspace, unbound by clearing its deletedAt. */
83		restoreCard: (card: KanbanCardRow) => void;
84		/** (RECYCLE-BIN) The unbound permanent destroy from inside the bin: hard-remove
85		 * the card row. A BOUND card's permanent destroy is the shared branch dialog
86		 * (the reconcile then drops the card) — wired in KanbanCard, not here. */
87		deletePermanentlyCard: (card: KanbanCardRow) => void;
88		/** (KANBAN COMPLETED) Drop into the Completed column: stamps completedAt
89		 * (the report datum + sidebar-hide flag) and snapshots title/context. */
90		completeCard: (card: KanbanCardRow) => void;
91		/** Drag out of the Completed column: clears the stamps and moves the card
92		 * into `toColumnId` (the board's reorder pass then places it precisely). */
93		uncompleteCard: (card: KanbanCardRow, toColumnId: string) => void;
94		updateCompletedDate: (cardId: string, completedAt: number) => void;
95		/** Delete a Completed-column record with no live branch (unbound task or a
96		 * frozen record). Bound cards with a live branch delete via the branch
97		 * dialog — the record then survives frozen, by design. */
98		deleteCompletedCard: (cardId: string) => void;
99		setColumnCompletedFilter: (
100			columnId: string,
101			filter:
102				| { kind: "all" }
103				| { kind: "last-month" }
104				| { kind: "custom"; fromMs: number; toMs: number },
105		) => void;
106	}
107	
108	/**
109	 * All Kanban mutators. Bound-card snooze/archive delegate to the EXISTING
110	 * sidebar state (one source of truth keyed by workspaceId); unbound (Queued)
111	 * cards carry their own fields. Deleting a bound card's branch is handled by the
112	 * shared DeleteWorkspaceDialog (the board's reconcile then drops the card).
113	 */
114	export function useKanbanActions(): UseKanbanActionsResult {
115		const collections = useCollections();
116		const {
117			archiveWorkspace,
118			completeWorkspace,
119			deleteWorkspace,
120			restoreWorkspace,
121			snoozeWorkspace,
122			uncompleteWorkspace,
123			unsnoozeWorkspace,
124			unarchiveWorkspaces,
125			ensureWorkspaceInSidebar,
126		} = useDashboardSidebarState();
127	
128		// Projects are fully local now — sourced from the host fan-out
129		// (useHostProjects), keyed by projectKey which equals a workspace's
130		// projectId. Upstream retired the `v2Projects` Electric collection.
131		const { projects: hostProjects } = useHostProjects();
132		const projectNameById = useMemo(() => {
133			const map = new Map<string, string>();
134			for (const p of hostProjects) map.set(p.projectKey, p.name);
135			return map;
136		}, [hostProjects]);
137	
138		const columnCards = useCallback(
139			(columnId: string) =>
140				Array.from(collections.v2KanbanCards.state.values()).filter(
141					(c) => c.columnId === columnId,
142				),
143			[collections],
144		);
145	
146		const customColumnsOrdered = useCallback(
147			() =>
148				Array.from(collections.v2KanbanColumns.state.values())
149					.filter(
150						(c) =>
151							!c.isQueue &&
152							c.id !== KANBAN_QUEUE_COLUMN_ID &&
153							!c.isCompleted &&
154							c.id !== KANBAN_COMPLETED_COLUMN_ID,
155					)
156					.sort((a, b) => a.tabOrder - b.tabOrder),
157			[collections],
158		);
159	
160		const ensureBoundRow = useCallback(
161			(workspaceId: string) => {
162				if (collections.v2WorkspaceLocalState.get(workspaceId)) return;
163				const ws = collections.v2Workspaces.get(workspaceId);
164				if (ws) ensureWorkspaceInSidebar(workspaceId, ws.projectId);
165			},
166			[collections, ensureWorkspaceInSidebar],
167		);
168	
169		const createQueuedCard = useCallback(
170			(title?: string) => {
171				const id = crypto.randomUUID();
172				const tabOrder = getNextTabOrder(columnCards(KANBAN_QUEUE_COLUMN_ID));
173				collections.v2KanbanCards.insert({
174					id,
175					columnId: KANBAN_QUEUE_COLUMN_ID,
176					tabOrder,
177					title: title ?? "",
178					description: null,
179					deadline: null,
180					deadlineTabOrder: null,
181					workspaceId: null,
182					snoozeUntil: null,
183					snoozeLaunchId: null,
184					archivedAt: null,
185					completedAt: null,
186					completedContext: null,
187					createdAt: Date.now(),
188				});
189				return id;
190			},
191			[collections, columnCards],
192		);
193	
194		const updateCard = useCallback<UseKanbanActionsResult["updateCard"]>(
195			(cardId, patch) => {
196				if (!collections.v2KanbanCards.get(cardId)) return;
197				collections.v2KanbanCards.update(cardId, (draft) =>
198					applyKanbanCardPatch(draft, patch),
199				);
200			},
201			[collections],
202		);
203	
204		const canDropCard = useCallback<UseKanbanActionsResult["canDropCard"]>(
205			(card, toColumnId, workspaceType) => {
206				const toQueue = toColumnId === KANBAN_QUEUE_COLUMN_ID;
207				// (KANBAN COMPLETED) ANY card can complete except a repo's main
208				// workspace (completing hides the sidebar row — a hidden main has no
209				// restore path since un-completion is dragging the card back out, and
210				// main rows must always be reachable). Unbound cards complete directly
211				// — completing a task is NOT a promote (no branch gets created).
212				if (toColumnId === KANBAN_COMPLETED_COLUMN_ID) {
213					return workspaceType === "main" ? "reject" : "ok";
214				}
215				if (card.workspaceId) {
216					// A bound (branch) card can never enter the unbound-only Queue.
217					return toQueue ? "reject" : "ok";
218				}
219				// An unbound (Queued) card leaving the Queue must bind to a branch.
220				return toQueue ? "ok" : "promote";
221			},
222			[],
223		);
224	
225		const applyCardOrder = useCallback(
226			(columnId: string, orderedCardIds: string[]) => {
227				// Batched update: one transaction = ONE localStorage flush for the whole
228				// column (the driver re-serializes the entire per-org blob per
229				// transaction, so per-card updates paid N flushes per drop).
230				const ids = orderedCardIds.filter((id) =>
231					collections.v2KanbanCards.get(id),
232				);
233				if (ids.length === 0) return;
234				collections.v2KanbanCards.update(ids, (drafts) => {
235					drafts.forEach((draft, index) => {
236						// (DEADLINE-TIE-ORDER) a card entering a DIFFERENT column arrives
237						// in that column's tie groups as a NEW item; same-column manual
238						// reorders never touch the deadline-mode order.
239						if (draft.columnId !== columnId) draft.deadlineTabOrder = null;
240						draft.columnId = columnId;
241						draft.tabOrder = index + 1;
242					});
243				});
244			},
245			[collections],
246		);
247	
248		const applyDeadlineTieOrder = useCallback(
249			(orderedCardIds: string[], resetCardIds: string[] = []) => {
250				// (DEADLINE-TIE-ORDER) Persist a drag done in deadline sort mode:
251				// numbers the dragged card's whole displayed tie group, and RESETS the
252				// group's hidden (snoozed/archived) members to null — their placement
253				// context changed while hidden, so they return as new arrivals at the
254				// bottom instead of interleaving with a stale number. NEVER touches
255				// tabOrder — the manual order survives mode round-trips. One batched
256				// transaction = one localStorage flush.
257				const orderIds = orderedCardIds.filter((id) =>
258					collections.v2KanbanCards.get(id),
259				);
260				const resetIds = resetCardIds.filter(
261					(id) => !orderIds.includes(id) && collections.v2KanbanCards.get(id),
262				);
263				const ids = [...orderIds, ...resetIds];
264				if (ids.length === 0) return;
265				collections.v2KanbanCards.update(ids, (drafts) => {
266					drafts.forEach((draft, index) => {
267						draft.deadlineTabOrder = index < orderIds.length ? index + 1 : null;
268					});
269				});
270			},
271			[collections],
272		);
273	
274		const moveCardToColumn = useCallback(
275			(cardId: string, toColumnId: string) => {
276				if (!collections.v2KanbanCards.get(cardId)) return;
277				const tabOrder = getNextTabOrder(columnCards(toColumnId));
278				collections.v2KanbanCards.update(cardId, (draft) => {
279					draft.columnId = toColumnId;
280					draft.tabOrder = tabOrder;
281					// (DEADLINE-TIE-ORDER) new column = new tie groups; arrive as a
282					// NEW item (below the explicitly ordered cards of its group).
283					draft.deadlineTabOrder = null;
284				});
285			},
286			[collections, columnCards],
287		);
288	
289		const completePromote = useCallback(
290			(queuedCardId: string, workspaceId: string, toColumnId: string) => {
291				const queued = collections.v2KanbanCards.get(queuedCardId);
292				// Fail fast: only promote an existing UNBOUND card into a real non-Queue
293				// column (guards against stale dialogs). NOTE: we do NOT require the
294				// v2Workspaces row to exist yet — the caller awaited a confirmed create
295				// outcome, but the optimistic/synced row may lag a tick; the bound card
296				// is keyed by workspaceId and reconcile aligns it.
297				if (!queued || queued.workspaceId) return;
298				const targetColumn = collections.v2KanbanColumns.get(toColumnId);
299				// Completed is no promote target either: a freshly-created branch must
300				// never be born completed (drops on Completed return "ok", not
301				// "promote", so this is unreachable via the board — belt and braces).
302				if (!targetColumn || targetColumn.isQueue || targetColumn.isCompleted) {
303					return;
304				}
305				const tabOrder = getNextTabOrder(columnCards(toColumnId));
306				const boundId = kanbanBoundCardId(workspaceId);
307				const existing = collections.v2KanbanCards.get(boundId);
308				if (existing) {
309					// Merge the Queued task metadata into the branch's existing card
310					// (non-git main, or a git branch-name collision). One card per branch.
311					collections.v2KanbanCards.update(boundId, (draft) => {
312						// (DEADLINE-TIE-ORDER) merged into a different column or tie
313						// group → arrives as a NEW item; an in-place merge keeps its order.
314						const columnChanged = draft.columnId !== toColumnId;
315						const deadlineChanged =
316							queued?.deadline != null && queued.deadline !== draft.deadline;
317						draft.columnId = toColumnId;
318						draft.tabOrder = tabOrder;
319						if (queued?.title) draft.title = queued.title;
320						if (queued?.description != null)
321							draft.description = queued.description;
322						if (queued?.deadline != null) draft.deadline = queued.deadline;
323						if (columnChanged || deadlineChanged) draft.deadlineTabOrder = null;
324					});
325				} else {
326					collections.v2KanbanCards.insert({
327						id: boundId,
328						columnId: toColumnId,
329						tabOrder,
330						title: queued?.title || "",
331						description: queued?.description ?? null,
332						deadline: queued?.deadline ?? null,
333						deadlineTabOrder: null,
334						workspaceId,
335						snoozeUntil: null,
336						snoozeLaunchId: null,
337						archivedAt: null,
338						// Promoting a completed task REOPENS it — the new branch card
339						// deliberately carries no completedAt (same on the merge path
340						// above, which never copies completion fields).
341						completedAt: null,
342						completedContext: null,
343						createdAt: Date.now(),
344					});
345				}
346				if (queued) collections.v2KanbanCards.delete(queuedCardId);
347			},
348			[collections, columnCards],
349		);
350	
351		// (PROMOTE-OPTIMISTIC) The promote dialog binds the card to the OPTIMISTIC
352		// workspace id and closes as soon as the create is submitted (the sidebar
353		// flow never blocks on persistence either — `completed` resolves only after
354		// the sync round-trip). These two actions are its background continuations.
355	
356		const restoreQueuedCard = useCallback(
357			(snapshot: KanbanCardRow, optimisticWorkspaceId: string) => {
358				// The create FAILED: the optimistic workspace row rolled back (reconcile
359				// drops the bound card) — put the task back in Queued so it's never lost.
360				const boundId = kanbanBoundCardId(optimisticWorkspaceId);
361				if (collections.v2KanbanCards.get(boundId)) {
362					collections.v2KanbanCards.delete(boundId);
363				}
364				if (collections.v2KanbanCards.get(snapshot.id)) return;
365				// (KANBAN COMPLETED) a completed task whose reopen-promote failed goes
366				// back where it was — the Completed column, stamps intact (the spread
367				// carries completedAt/completedContext) — not into Queued.
368				const restoreColumnId =
369					snapshot.completedAt != null
370						? KANBAN_COMPLETED_COLUMN_ID
371						: KANBAN_QUEUE_COLUMN_ID;
372				collections.v2KanbanCards.insert({
373					...snapshot,
374					columnId: restoreColumnId,
375					tabOrder: getNextTabOrder(columnCards(restoreColumnId)),
376					deadlineTabOrder: null,
377					workspaceId: null,
378				});
379			},
380			[collections, columnCards],
381		);
382	
383		const rebindPromotedCard = useCallback(
384			(fromWorkspaceId: string, toWorkspaceId: string) => {
385				// The host persisted the create under a DIFFERENT id than the optimistic
386				// one — bound card ids derive from the workspace id, so move the card.
387				if (fromWorkspaceId === toWorkspaceId) return;
388				const fromId = kanbanBoundCardId(fromWorkspaceId);
389				const from = collections.v2KanbanCards.get(fromId);
390				if (!from) return;
391				collections.v2KanbanCards.delete(fromId);
392				const toId = kanbanBoundCardId(toWorkspaceId);
393				const existing = collections.v2KanbanCards.get(toId);
394				if (existing) {
395					// The mirror already auto-created the real card — merge, one per branch.
396					collections.v2KanbanCards.update(toId, (draft) => {
397						draft.columnId = from.columnId;
398						draft.tabOrder = from.tabOrder;
399						// Placement copies are unconditional (the optimistic card is the
400						// one the user arranged); null correctly means "never ordered".
401						draft.deadlineTabOrder = from.deadlineTabOrder;
402						if (from.title) draft.title = from.title;
403						if (from.description != null) draft.description = from.description;
404						if (from.deadline != null) draft.deadline = from.deadline;
405					});
406					return;
407				}
408				collections.v2KanbanCards.insert({
409					...from,
410					id: toId,
411					workspaceId: toWorkspaceId,
412				});
413			},
414			[collections],
415		);
416	
417		const addColumn = useCallback(
418			(name?: string) => {
419				const id = crypto.randomUUID();
420				const tabOrder = getNextTabOrder(customColumnsOrdered());
421				collections.v2KanbanColumns.insert({
422					id,
423					name: name ?? "New column",
424					tabOrder,
425					isQueue: false,
426					isCompleted: false,
427					sortMode: "manual",
428					completedFilter: "all",
429					completedFilterFrom: null,
430					completedFilterTo: null,
431					showSnoozed: false,
432					showArchived: false,
433					snoozedCollapsed: false,
434					archivedCollapsed: false,
435					createdAt: Date.now(),
436				});
437				return id;
438			},
439			[collections, customColumnsOrdered],
440		);
441	
442		const renameColumn = useCallback(
443			(columnId: string, name: string) => {
444				if (!collections.v2KanbanColumns.get(columnId)) return;
445				collections.v2KanbanColumns.update(columnId, (draft) => {
446					draft.name = name;
447				});
448			},
449			[collections],
450		);
451	
452		const deleteColumn = useCallback(
453			(columnId: string): DeleteColumnResult => {
454				const ordered = customColumnsOrdered().map((c) => c.id);
455				const { allowed, targetColumnId } = getColumnDeleteTarget(
456					ordered,
457					columnId,
458				);
459				if (!allowed || !targetColumnId) {
460					return {
461						ok: false,
462						reason: "Cannot delete the last custom column.",
463					};
464				}
465				// Move this column's cards to the target column (append, renumber).
466				const moving = columnCards(columnId).sort(
467					(a, b) => a.tabOrder - b.tabOrder,
468				);
469				let order = getNextTabOrder(columnCards(targetColumnId));
470				for (const card of moving) {
471					collections.v2KanbanCards.update(card.id, (draft) => {
472						draft.columnId = targetColumnId;
473						draft.tabOrder = order;
474					});
475					order += 1;
476				}
477				collections.v2KanbanColumns.delete(columnId);
478				return { ok: true };
479			},
480			[collections, columnCards, customColumnsOrdered],
481		);
482	
483		const reorderColumns = useCallback(
484			(orderedCustomIds: string[]) => {
485				orderedCustomIds.forEach((columnId, index) => {
486					if (!collections.v2KanbanColumns.get(columnId)) return;
487					collections.v2KanbanColumns.update(columnId, (draft) => {
488						draft.tabOrder = index + 1;
489					});
490				});
491			},
492			[collections],
493		);
494	
495		const setColumnSortMode = useCallback(
496			(columnId: string, mode: "manual" | "deadline") => {
497				if (!collections.v2KanbanColumns.get(columnId)) return;
498				collections.v2KanbanColumns.update(columnId, (draft) => {
499					draft.sortMode = mode;
500				});
501			},
502			[collections],
503		);
504	
505		const setColumnSectionFlag = useCallback<
506			UseKanbanActionsResult["setColumnSectionFlag"]
507		>(
508			(columnId, field, value) => {
509				if (!collections.v2KanbanColumns.get(columnId)) return;
510				collections.v2KanbanColumns.update(columnId, (draft) => {
511					draft[field] = value;
512				});
513			},
514			[collections],
515		);
516	
517		const snoozeCard = useCallback(
518			(card: KanbanCardRow, until: number | "next-launch") => {
519				if (card.workspaceId) {
520					ensureBoundRow(card.workspaceId);
521					snoozeWorkspace(card.workspaceId, until);
522					return;
523				}
524				if (!collections.v2KanbanCards.get(card.id)) return;
525				collections.v2KanbanCards.update(card.id, (draft) => {
526					if (until === "next-launch") {
527						// Same "until next launch" sentinel as the sidebar: store this
528						// launch's id; on the next launch APP_LAUNCH_ID differs and the
529						// card is no longer snoozed (cleared by useKanbanData's ticker).
530						draft.snoozeUntil = null;
531						draft.snoozeLaunchId = APP_LAUNCH_ID;
532					} else {
533						draft.snoozeUntil = until;
534						draft.snoozeLaunchId = null;
535					}
536					draft.archivedAt = null;
537				});
538			},
539			[collections, snoozeWorkspace, ensureBoundRow],
540		);
541	
542		const unsnoozeCard = useCallback(
543			(card: KanbanCardRow) => {
544				if (card.workspaceId) {
545					unsnoozeWorkspace(card.workspaceId);
546					return;
547				}
548				if (!collections.v2KanbanCards.get(card.id)) return;
549				collections.v2KanbanCards.update(card.id, (draft) => {
550					draft.snoozeUntil = null;
551					draft.snoozeLaunchId = null;
552				});
553			},
554			[collections, unsnoozeWorkspace],
555		);
556	
557		const archiveCard = useCallback(
558			(card: KanbanCardRow) => {
559				if (card.workspaceId) {
560					ensureBoundRow(card.workspaceId);
561					archiveWorkspace(card.workspaceId);
562					return;
563				}
564				if (!collections.v2KanbanCards.get(card.id)) return;
565				collections.v2KanbanCards.update(card.id, (draft) => {
566					draft.archivedAt = Date.now();
567					draft.snoozeUntil = null;
568					draft.snoozeLaunchId = null;
569				});
570			},
571			[collections, archiveWorkspace, ensureBoundRow],
572		);
573	
574		const unarchiveCard = useCallback(
575			(card: KanbanCardRow) => {
576				if (card.workspaceId) {
577					unarchiveWorkspaces([card.workspaceId]);
578					return;
579				}
580				if (!collections.v2KanbanCards.get(card.id)) return;
581				collections.v2KanbanCards.update(card.id, (draft) => {
582					draft.archivedAt = null;
583				});
584			},
585			[collections, unarchiveWorkspaces],
586		);
587	
588		// (RECYCLE-BIN) Soft delete is the DEFAULT card "Delete" now — silent,
589		// reversible, visual-only (worktree/branch/sessions untouched). Bound cards
590		// delegate to the branch's sidebarState (one source of truth via
591		// deleteWorkspace); unbound (Queued) cards stamp their own deletedAt. The
592		// permanent git-destroy is relocated to "Delete permanently" inside the bin.
593	
594		const deleteCard = useCallback(
595			(card: KanbanCardRow) => {
596				if (card.workspaceId) {
597					ensureBoundRow(card.workspaceId);
598					deleteWorkspace(card.workspaceId);
599					return;
600				}
601				if (!collections.v2KanbanCards.get(card.id)) return;
602				collections.v2KanbanCards.update(card.id, (draft) => {
603					draft.deletedAt = Date.now();
604					// Clear the other hide states so a re-delete after a restore lands
605					// cleanly in the bin with a fresh timestamp (mirrors deleteWorkspace).
606					draft.snoozeUntil = null;
607					draft.snoozeLaunchId = null;
608					draft.archivedAt = null;
609				});
610			},
611			[collections, deleteWorkspace, ensureBoundRow],
612		);
613	
614		const restoreCard = useCallback(
615			(card: KanbanCardRow) => {
616				if (card.workspaceId) {
617					restoreWorkspace(card.workspaceId);
618					return;
619				}
620				if (!collections.v2KanbanCards.get(card.id)) return;
621				collections.v2KanbanCards.update(card.id, (draft) => {
622					// Full restore-to-active (mirrors restoreWorkspace): clear every hide
623					// state, not just deletedAt, so the card re-enters its column's active
624					// list regardless of what it was before deletion.
625					draft.deletedAt = null;
626					draft.archivedAt = null;
627					draft.snoozeUntil = null;
628					draft.snoozeLaunchId = null;
629					draft.completedAt = null;
630					draft.completedContext = null;
631				});
632			},
633			[collections, restoreWorkspace],
634		);
635	
636		const deletePermanentlyCard = useCallback(
637			(card: KanbanCardRow) => {
638				// Unbound only — a BOUND card's permanent destroy is the shared branch
639				// dialog (the reconcile drops the card once the workspace row is gone).
640				if (card.workspaceId) return;
641				const current = collections.v2KanbanCards.get(card.id);
642				if (!current) return;
643				// Guard the bin boundary: only the in-bin permanent destroy can hard-remove
644				// a row. A non-deleted card reaching here (stale menu/race) must NOT be
645				// silently nuked — its soft-delete is the only path to the bin.
646				if (current.deletedAt == null) return;
647				collections.v2KanbanCards.delete(card.id);
648			},
649			[collections],
650		);
651	
652		// (KANBAN COMPLETED) Card transaction FIRST, sidebar second — each update is
653		// its own localStorage flush, and the reconcile's heal rules converge toward
654		// the CARD's column, so a crash between the two transactions self-repairs in
655		// the direction the user dragged.
656	
657		const completeCard = useCallback(
658			(card: KanbanCardRow) => {
659				if (!collections.v2KanbanCards.get(card.id)) return;
660				const completedAt = Date.now();
661				if (card.workspaceId) {
662					const ws = collections.v2Workspaces.get(card.workspaceId);
663					// Main workspaces are never completable (canDropCard rejects the
664					// drop; this keeps any other caller honest).
665					if (ws?.type === "main") return;
666					const projectName = ws
667						? (projectNameById.get(ws.projectId) ?? null)
668						: null;
669					collections.v2KanbanCards.update(card.id, (draft) => {
670						draft.columnId = KANBAN_COMPLETED_COLUMN_ID;
671						draft.tabOrder = 0; // unused there — Completed is date-sorted
672						draft.deadlineTabOrder = null;
673						draft.completedAt = completedAt;
674						if (ws) {
675							// Snapshot title + context NOW so the record stays meaningful
676							// if the branch is later deleted (frozen record).
677							draft.title = deriveCardTitle(ws);
678							draft.completedContext = buildCompletedContext(
679								projectName,
680								ws.branch,
681							);
682						}
683					});
684					if (ws) {
685						ensureBoundRow(card.workspaceId);
686						completeWorkspace(card.workspaceId, completedAt);
687					}
688					return;
689				}
690				collections.v2KanbanCards.update(card.id, (draft) => {
691					draft.columnId = KANBAN_COMPLETED_COLUMN_ID;
692					draft.tabOrder = 0;
693					draft.deadlineTabOrder = null;
694					draft.completedAt = completedAt;
695					// Completing is terminal for the hide states — a completed task is
696					// neither snoozed nor archived.
697					draft.snoozeUntil = null;
698					draft.snoozeLaunchId = null;
699					draft.archivedAt = null;
700				});
701			},
702			[collections, completeWorkspace, ensureBoundRow, projectNameById],
703		);
704	
705		const uncompleteCard = useCallback(
706			(card: KanbanCardRow, toColumnId: string) => {
707				if (!collections.v2KanbanCards.get(card.id)) return;
708				const tabOrder = getNextTabOrder(columnCards(toColumnId));
709				collections.v2KanbanCards.update(card.id, (draft) => {
710					draft.columnId = toColumnId;
711					draft.tabOrder = tabOrder;
712					draft.deadlineTabOrder = null;
713					draft.completedAt = null;
714					draft.completedContext = null;
715				});
716				if (card.workspaceId) uncompleteWorkspace(card.workspaceId);
717			},
718			[collections, columnCards, uncompleteWorkspace],
719		);
720	
721		const updateCompletedDate = useCallback(
722			(cardId: string, completedAt: number) => {
723				if (!collections.v2KanbanCards.get(cardId)) return;
724				collections.v2KanbanCards.update(cardId, (draft) => {
725					draft.completedAt = completedAt;
726				});
727			},
728			[collections],
729		);
730	
731		const deleteCompletedCard = useCallback(
732			(cardId: string) => {
733				const card = collections.v2KanbanCards.get(cardId);
734				if (!card || card.columnId !== KANBAN_COMPLETED_COLUMN_ID) return;
735				// A bound card with a LIVE branch deletes via the branch dialog (and
736				// then survives frozen) — this action is only for records with no
737				// branch left: unbound tasks and frozen records.
738				if (card.workspaceId && collections.v2Workspaces.get(card.workspaceId)) {
739					return;
740				}
741				collections.v2KanbanCards.delete(cardId);
742			},
743			[collections],
744		);
745	
746		const setColumnCompletedFilter = useCallback<
747			UseKanbanActionsResult["setColumnCompletedFilter"]
748		>(
749			(columnId, filter) => {
750				const column = collections.v2KanbanColumns.get(columnId);
751				if (!column || !column.isCompleted) return;
752				collections.v2KanbanColumns.update(columnId, (draft) => {
753					draft.completedFilter = filter.kind;
754					if (filter.kind === "custom") {
755						// The range calendar always yields from <= to; normalise anyway so
756						// a stored range can never be inverted.
757						draft.completedFilterFrom = Math.min(filter.fromMs, filter.toMs);
758						draft.completedFilterTo = Math.max(filter.fromMs, filter.toMs);
759					} else {
760						draft.completedFilterFrom = null;
761						draft.completedFilterTo = null;
762					}
763				});
764			},
765			[collections],
766		);
767	
768		return useMemo(
769			() => ({
770				createQueuedCard,
771				updateCard,
772				canDropCard,
773				applyCardOrder,
774				applyDeadlineTieOrder,
775				moveCardToColumn,
776				completePromote,
777				restoreQueuedCard,
778				rebindPromotedCard,
779				addColumn,
780				renameColumn,
781				deleteColumn,
782				reorderColumns,
783				setColumnSortMode,
784				setColumnSectionFlag,
785				snoozeCard,
786				unsnoozeCard,
787				archiveCard,
788				unarchiveCard,
789				deleteCard,
790				restoreCard,
791				deletePermanentlyCard,
792				completeCard,
793				uncompleteCard,
794				updateCompletedDate,
795				deleteCompletedCard,
796				setColumnCompletedFilter,
797			}),
798			[
799				createQueuedCard,
800				updateCard,
801				canDropCard,
802				applyCardOrder,
803				applyDeadlineTieOrder,
804				moveCardToColumn,
805				completePromote,
806				restoreQueuedCard,
807				rebindPromotedCard,
808				addColumn,
809				renameColumn,
810				deleteColumn,
811				reorderColumns,
812				setColumnSortMode,
813				setColumnSectionFlag,
814				snoozeCard,
815				unsnoozeCard,
816				archiveCard,
817				unarchiveCard,
818				deleteCard,
819				restoreCard,
820				deletePermanentlyCard,
821				completeCard,
822				uncompleteCard,
823				updateCompletedDate,
824				deleteCompletedCard,
825				setColumnCompletedFilter,
826			],
827		);
828	}
