1	import { getEventBus } from "@superset/workspace-client";
2	import { useLiveQuery } from "@tanstack/react-db";
3	import { useQueries, useQueryClient } from "@tanstack/react-query";
4	import { useEffect, useMemo, useState } from "react";
5	import { useRelayUrl } from "renderer/hooks/useRelayUrl";
6	import { getHostServiceWsToken } from "renderer/lib/host-service-auth";
7	import { getHostServiceClientByUrl } from "renderer/lib/host-service-client";
8	import { useCollections } from "renderer/routes/_authenticated/providers/CollectionsProvider";
9	import { useLocalHostService } from "renderer/routes/_authenticated/providers/LocalHostServiceProvider";
10	import {
11		applyWorkspaceChangedEvent,
12		deriveHostWorkspacesQueryTargets,
13		getHostWorkspacesQueryKey,
14		type HostWorkspaceItem,
15		type HostWorkspaceRow,
16		loadHostWorkspacesSnapshot,
17		mergeHostWorkspaces,
18		saveHostWorkspacesSnapshot,
19	} from "./useHostWorkspaces.utils";
20	
21	export type { HostWorkspaceItem } from "./useHostWorkspaces.utils";
22	
23	const WORKSPACES_FALLBACK_REFETCH_INTERVAL_MS = 30_000;
24	
25	export interface HostWorkspacesCacheOps {
26		/** Resolve the URL to reach the host owning `hostId` (null = unreachable). */
27		resolveHostUrl: (hostId: string) => string | null;
28		/**
29		 * Optimistically upsert a row into a host's cached list. The host's
30		 * `workspace:changed` broadcast (or the next refetch) converges the
31		 * cache onto the real row.
32		 */
33		upsertWorkspace: (row: HostWorkspaceRow) => void;
34		/** Optimistically drop a row from a host's cached list. */
35		removeWorkspace: (hostId: string, workspaceId: string) => void;
36		/** Rollback hammer: refetch a host's list after a failed write. */
37		invalidateHost: (hostId: string) => void;
38	}
39	
40	export interface UseHostWorkspacesResult {
41		workspaces: HostWorkspaceItem[];
42		/**
43		 * True once every host answered, failed, or served a snapshot. Gates
44		 * empty states only — existing rows always render (cache-first rule).
45		 */
46		isReady: boolean;
47		cache: HostWorkspacesCacheOps;
48	}
49	
50	/**
51	 * The workspace read path: fan out `workspace.list` to every known host
52	 * (local direct, remote via relay), merge, live-update from each host's
53	 * `workspace:changed` events, and persist last-seen lists per host to
54	 * IndexedDB so remote machines still render offline.
55	 *
56	 * Cloud rows from the still-synced Electric collection fill in only for
57	 * hosts that served nothing (pre-R1 builds, no snapshot) — that fallback
58	 * disappears in R3.
59	 *
60	 * Runs once inside HostWorkspacesProvider; consumers read the shared
61	 * result via that provider's useHostWorkspaces.
62	 */
63	export function useHostWorkspacesSource(): UseHostWorkspacesResult {
64		const collections = useCollections();
65		const queryClient = useQueryClient();
66		const { activeHostUrl, machineId } = useLocalHostService();
67		const relayUrl = useRelayUrl();
68	
69		const { data: hosts = [] } = useLiveQuery(
70			(q) =>
71				q.from({ hosts: collections.v2Hosts }).select(({ hosts }) => ({
72					organizationId: hosts.organizationId,
73					machineId: hosts.machineId,
74					isOnline: hosts.isOnline,
75				})),
76			[collections],
77		);
78	
79		const { data: cloudRows = [] } = useLiveQuery(
80			(q) => q.from({ workspaces: collections.v2Workspaces }),
